[correct]

pos[4][3].event = 2;

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] map.isPartition(5, 0, "e")

[if exp='! game.party.hasItem(o.時のスイッチ)']
	@notice text="I hear a voice from somewhere:<y><r>This door will not be opened to those without a <p>Time Switch<y>."
	[eventoff]
[endif]

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=5 y=0 way=e mode=open

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove && ! party.isFloating() && map.getWallInfo(2, 3, "w").type == "wall"

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=2 y=3 way=w mode=open

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] party.lastIsMove

@eval exp='tf.temp = game.map.getWallInfo(2, 3, "w")'
[if exp='game.map.getFloorInfo(4, 3).type == "movable"']
	[if exp='tf.temp.type == "wall"']
		@wait time=800
		@se f=fence
		@switchfence x=2 y=3 way=w mode=open
	[endif]
[elsif exp='tf.temp.type == "space"']
	@wait time=800
	@se f=fence
	@switchfence x=2 y=3 way=w mode=close
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@notice text="When something touches the red floor, the door opens."

[eventoff]
;-------------------------------------------------------------------------------
*reset_floor

@se f=dragstone
@eval exp='game.map.reset()'
@wait time=800
@warp x=4 y=0 way=e
@notice text="All the stones on the floor have returned to their original positions. You were warped back to near the entrance!"

[eventoff]
;===============================================================================
